// Register page
import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { LogoFull } from '../components/Logo';
import s from './Auth.module.css';

export default function Register() {
  const nav = useNavigate();
  const { register } = useAuth();
  const [form, setForm] = useState({ username: '', email: '', password: '', confirm: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const onChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const onSubmit = async e => {
    e.preventDefault();
    setError('');
    if (form.password !== form.confirm) return setError('Les mots de passe ne correspondent pas.');
    if (form.password.length < 6) return setError('Mot de passe trop court (min 6 caractères).');
    setLoading(true);
    try {
      await register(form.username, form.email, form.password);
      nav('/chat');
    } catch (err) {
      setError(err.response?.data?.detail || "Erreur lors de l'inscription.");
    } finally { setLoading(false); }
  };

  return (
    <div className={s.page}>
      <div className={s.bg1} /><div className={s.bg2} />
      <Link to="/" className={s.back}>← Accueil</Link>
      <div className={s.card}>
        <div className={s.cardLogo}><LogoFull size={32} /></div>
        <h1 className={s.title}>Créer un compte</h1>
        <p className={s.sub}>Rejoignez AWAL GPT et commencez à chatter en Tamazight.</p>
        {error && <div className={s.err}>{error}</div>}
        <form onSubmit={onSubmit} className={s.form}>
          <div className={s.field}>
            <label className={s.label}>Nom d'utilisateur</label>
            <input className={s.input} type="text" name="username" placeholder="Votre nom"
              value={form.username} onChange={onChange} required />
          </div>
          <div className={s.field}>
            <label className={s.label}>Email</label>
            <input className={s.input} type="email" name="email" placeholder="votre@email.com"
              value={form.email} onChange={onChange} required />
          </div>
          <div className={s.field}>
            <label className={s.label}>Mot de passe</label>
            <input className={s.input} type="password" name="password" placeholder="Min. 6 caractères"
              value={form.password} onChange={onChange} required />
          </div>
          <div className={s.field}>
            <label className={s.label}>Confirmer</label>
            <input className={s.input} type="password" name="confirm" placeholder="••••••••"
              value={form.confirm} onChange={onChange} required />
          </div>
          <button className={s.submit} disabled={loading}>
            {loading ? 'Création...' : 'Créer mon compte →'}
          </button>
        </form>
        <p className={s.switch}>Déjà un compte ? <Link to="/login" className={s.link}>Se connecter</Link></p>
      </div>
    </div>
  );
}
